def classify(title, desc):
    text = (title + " " + desc).lower()
    scores = {cat: 0 for cat in keywords}
    
    # Simple scoring
    for cat, words in keywords.items():
        for word in words:
            # Check for word boundaries to avoid partial matches
            if f" {word} " in f" {text} " or text.startswith(word + " ") or text.endswith(" " + word):
                scores[cat] += 1
                
    # Penalties/Boosts
    if 'stock' in text or 'market' in text or 'oil' in text or 'economy' in text:
        scores['Business'] += 2
        scores['Sports'] -= 2 # Unlikely to be sports
        
    if 'iraq' in text or 'war' in text or 'bomb' in text:
        scores['World'] += 2
        scores['Sports'] -= 2

    if 'game' in text:
        if any(x in text for x in ['video', 'console', 'computer', 'software', 'nintendo', 'sony']):
            scores['Sci/Tech'] += 2
            scores['Sports'] -= 1
        elif any(x in text for x in ['team', 'win', 'score', 'player', 'coach', 'stadium']):
            scores['Sports'] += 2
            
    if 'olympic' in text or 'athens' in text:
        scores['Sports'] += 3

    # If scores['Sports'] is max, return 'Sports', else return something else
    best_cat = max(scores, key=scores.get)
    if scores[best_cat] > 0:
        return best_cat
    return 'Unknown'

sports = []
